@@ -44,0 +44,1 @@
+import org.jemmy.JemmyException;
@@ -314,1 +315,12 @@
-		selectContextOption(ACTION_DISCONNECT_TEXT, path);
+		int maxRetries = 5;
+		for (int i = 0; i < maxRetries; i++) {
+			try {
+				selectContextOption(ACTION_DISCONNECT_TEXT, path);
+				break;
+			} catch (JemmyException e) {
+				if (i == maxRetries - 1) {
+					throw e;
+				}
+				sleep(1000);
+			}
+		}
